using System.ClientModel;
using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations ---

/// <summary>Tools the agent can invoke during research.</summary>
static class ResearchTools
{
    private static readonly HttpClient s_http = new();
    private static readonly List<string> s_notes = [];

    [Description("Search the web for a query and return a list of result snippets. Use this to discover information about a topic.")]
    public static async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍  Searching: \"{query}\"");

        // Use DuckDuckGo instant-answer API (no key required)
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
        var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

        try
        {
            var response = await s_http.SendAsync(request);
            var html = await response.Content.ReadAsStringAsync();

            // Extract snippet text from result blocks
            var snippets = new List<string>();
            var marker = "result__snippet";
            var idx = 0;
            while (snippets.Count < 6 && (idx = html.IndexOf(marker, idx, StringComparison.Ordinal)) >= 0)
            {
                var gt = html.IndexOf('>', idx);
                if (gt < 0) break;
                var lt = html.IndexOf('<', gt);
                if (lt < 0) break;
                var text = WebUtility.HtmlDecode(html[(gt + 1)..lt].Trim());
                if (!string.IsNullOrWhiteSpace(text))
                    snippets.Add(text);
                idx = lt;
            }

            if (snippets.Count == 0)
                return "No results found. Try rephrasing the query.";

            return string.Join("\n\n", snippets.Select((s, i) => $"[{i + 1}] {s}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save an important finding or note for later use in the summary. Call this whenever you discover a key fact.")]
    public static string TakeNote(
        [Description("The note text to save")] string note)
    {
        s_notes.Add(note);
        Console.WriteLine($"  📝  Note #{s_notes.Count} saved");
        return $"Note #{s_notes.Count} saved.";
    }

    [Description("Retrieve all notes taken so far.")]
    public static string GetNotes()
    {
        if (s_notes.Count == 0)
            return "No notes taken yet.";

        return string.Join("\n", s_notes.Select((n, i) => $"[{i + 1}] {n}"));
    }

    public static void ClearNotes() => s_notes.Clear();
}

// --- Main program ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔬  Research Agent  🔬        ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or      ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

IChatClient chatClient = new OpenAIClient(new ApiKeyCredential(apiKey))
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new[]
{
    AIFunctionFactory.Create(ResearchTools.SearchWeb),
    AIFunctionFactory.Create(ResearchTools.TakeNote),
    AIFunctionFactory.Create(ResearchTools.GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

while (true)
{
    Console.Write("\n📌 Topic: ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    ResearchTools.ClearNotes();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, """
            You are a research agent. Given a topic, you MUST:
            1. Search the web multiple times with varied queries to gather broad information.
            2. Take notes on every key fact you discover.
            3. After gathering enough information (at least 3 searches), retrieve your notes
               and produce a well-structured summary with sections and bullet points.
            Always use your tools — do not rely on prior knowledge alone.
            """),
        new(ChatRole.User, $"Research this topic and provide a comprehensive summary: {topic}"),
    };

    Console.WriteLine($"\n🔬 Researching \"{topic}\"...\n");

    try
    {
        var response = await chatClient.GetResponseAsync(messages, chatOptions);
        Console.WriteLine("\n════════════════ Summary ════════════════\n");
        Console.WriteLine(response.Text);
        Console.WriteLine("\n═════════════════════════════════════════\n");
    }
    catch (Exception ex)
    {
        Console.Error.WriteLine($"\n❌ Error: {ex.Message}");
    }
}

Console.WriteLine("Goodbye! 👋");
return 0;

