 IChatClient chatClient = new OpenAIClient(new ApiKeyCredential(apiKey))
     .GetChatClient(model)
     .AsIChatClient()
     .AsBuilder()
     .UseFunctionInvocation()
     .Build();

 var tools = new[]
 {
     AIFunctionFactory.Create(ResearchTools.SearchWeb),
     AIFunctionFactory.Create(ResearchTools.TakeNote),
     AIFunctionFactory.Create(ResearchTools.GetNotes),
 };

 var chatOptions = new ChatOptions { Tools = [.. tools] };

 while (true)
 {
     Console.Write("\n📌 Topic: ");
     var topic = Console.ReadLine()?.Trim();
     if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
         break;

     ResearchTools.ClearNotes();

     var messages = new List<ChatMessage>
     {
         new(ChatRole.System, """
             You are a research agent. Given a topic, you MUST:
             1. Search the web multiple times with varied queries to gather broad information.
             2. Take notes on every key fact you discover.
             3. After gathering enough information (at least 3 searches), retrieve your notes
                and produce a well-structured summary with sections and bullet points.
             Always use your tools — do not rely on prior knowledge alone.
             """),
         new(ChatRole.User, $"Research this topic and provide a comprehensive summary: {topic}"),
     };

     Console.WriteLine($"\n🔬 Researching \"{topic}\"...\n");

     try
     {
         var response = await chatClient.GetResponseAsync(messages, chatOptions);
         Console.WriteLine("\n════════════════ Summary ════════════════\n");
