 /// <summary>Tools the agent can invoke during research.</summary>
 static class ResearchTools
 {
     private static readonly HttpClient s_http = new();
     private static readonly List<string> s_notes = [];

     [Description("Search the web for a query and return a list of result snippets. Use this to discover information about a topic.")]
     public static async Task<string> SearchWeb(
         [Description("The search query string")] string query)
     {
         Console.WriteLine($"  🔍  Searching: \"{query}\"");

         var encoded = WebUtility.UrlEncode(query);
         var url = $"https://html.duckduckgo.com/html/?q={encoded}";
         var request = new HttpRequestMessage(HttpMethod.Get, url);
         request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

         try
         {
             var response = await s_http.SendAsync(request);
             var html = await response.Content.ReadAsStringAsync();

             // Extract snippet text from result blocks
             var snippets = new List<string>();
             var marker = "result__snippet";
             var idx = 0;
             while (snippets.Count < 6 && (idx = html.IndexOf(marker, idx, StringComparison.Ordinal)) >= 0)
             {
                 var gt = html.IndexOf('>', idx);
                 if (gt < 0) break;
                 var lt = html.IndexOf('<', gt);
                 if (lt < 0) break;
                 var text = WebUtility.HtmlDecode(html[(gt + 1)..lt].Trim());
                 if (!string.IsNullOrWhiteSpace(text))
                     snippets.Add(text);
                 idx = lt;
             }

             if (snippets.Count == 0)
                 return "No results found. Try rephrasing the query.";

             return string.Join("\n\n", snippets.Select((s, i) => $"[{i + 1}] {s}"));
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}";
         }
     }

     [Description("Save an important finding or note for later use in the summary. Call this whenever you discover a key fact.")]
     public static string TakeNote(
         [Description("The note text to save")] string note)
     {
         s_notes.Add(note);
         Console.WriteLine($"  📝  Note #{s_notes.Count} saved");
         return $"Note #{s_notes.Count} saved.";
     }

     [Description("Retrieve all notes taken so far.")]
     public static string GetNotes()
     {
         if (s_notes.Count == 0)
             return "No notes taken yet.";

         return string.Join("\n", s_notes.Select((n, i) => $"[{i + 1}] {n}"));
     }

     public static void ClearNotes() => s_notes.Clear();
 }

